echo ""

# ============================================================================
# Phase 1: Check OAuth Connections in Database
# ============================================================================
echo -e "${YELLOW}Phase 1: Checking OAuth Connections${NC}"
echo ""

OAUTH_CONNECTIONS=$(curl -s -X POST "https://api.supabase.com/v1/projects/${PROJECT_REF}/database/query" \
  -H "Authorization: Bearer ${ACCESS_TOKEN}" \
  -H "Content-Type: application/json" \
  -d '{"query": "SELECT user_id, workspace_id, created_at FROM clickup_connections ORDER BY created_at DESC LIMIT 5"}')

echo "$OAUTH_CONNECTIONS" | jq -r 'if length > 0 then "✅ Found \(length) OAuth connection(s):\n" + ([.[] | "  - User: \(.user_id) | Workspace: \(.workspace_id) | Created: \(.created_at)"] | join("\n")) else "⚠️ No OAuth connections found in database" end'

echo ""
echo ""

# ============================================================================
# Phase 2: Get Test Job and User
# ============================================================================
echo -e "${YELLOW}Phase 2: Finding Test Job${NC}"
echo ""

# Get a job with Valcre job number (needed for ClickUp task creation)
TEST_JOB=$(curl -s -X POST "https://api.supabase.com/v1/projects/${PROJECT_REF}/database/query" \
  -H "Authorization: Bearer ${ACCESS_TOKEN}" \
  -H "Content-Type: application/json" \
  -d '{"query": "SELECT id, job_number, clickup_task_id FROM job_submissions WHERE job_number IS NOT NULL AND job_number LIKE '\''VAL%'\'' ORDER BY created_at DESC LIMIT 1"}')

JOB_ID=$(echo "$TEST_JOB" | jq -r '.[0].id // empty')
JOB_NUMBER=$(echo "$TEST_JOB" | jq -r '.[0].job_number // empty')
EXISTING_TASK_ID=$(echo "$TEST_JOB" | jq -r '.[0].clickup_task_id // empty')

if [ -z "$JOB_ID" ]; then
  echo -e "${RED}❌ No test job found with VAL number${NC}"
  echo "   Need a job with Valcre job number to test ClickUp task creation"
  exit 1
fi

echo -e "${GREEN}✅ Test job found:${NC}"
echo "   Job ID: $JOB_ID"
echo "   Job Number: $JOB_NUMBER"
if [ -n "$EXISTING_TASK_ID" ]; then
  echo -e "   ${YELLOW}⚠️ Already has ClickUp task: $EXISTING_TASK_ID${NC}"
  echo "   (Will test update-clickup-task instead)"
else
  echo "   ✅ No existing ClickUp task (can test create-clickup-task)"
fi

echo ""
echo ""

# ============================================================================
# Phase 3: Get User ID from OAuth Connection
# ============================================================================
echo -e "${YELLOW}Phase 3: Getting User ID for OAuth Test${NC}"
echo ""

USER_ID=$(echo "$OAUTH_CONNECTIONS" | jq -r '.[0].user_id // empty')
WORKSPACE_ID=$(echo "$OAUTH_CONNECTIONS" | jq -r '.[0].workspace_id // empty')

if [ -z "$USER_ID" ]; then
  echo -e "${YELLOW}⚠️ No OAuth connection found - will test fallback behavior${NC}"
  echo "   Edge Function should use env var token when userId is null"
  USER_ID="null"
else
  echo -e "${GREEN}✅ OAuth connection found:${NC}"
  echo "   User ID: $USER_ID"
  echo "   Workspace ID: $WORKSPACE_ID"
fi

echo ""
echo ""

# ============================================================================
# Phase 4: Test Edge Function with userId
# ============================================================================
echo -e "${YELLOW}Phase 4: Testing Edge Function with userId${NC}"
echo ""

if [ -n "$EXISTING_TASK_ID" ]; then
  echo "Testing update-clickup-task (job already has task)..."
  FUNCTION_NAME="update-clickup-task"
else
  echo "Testing create-clickup-task..."
  FUNCTION_NAME="create-clickup-task"
fi

echo ""
echo "Calling Edge Function with:"
echo "  jobId: $JOB_ID"
echo "  userId: ${USER_ID:-null}"
echo ""

# Call Edge Function via Supabase API
RESPONSE=$(curl -s -X POST "${SUPABASE_URL}/functions/v1/${FUNCTION_NAME}" \
  -H "Authorization: Bearer ${SUPABASE_ANON_KEY}" \
  -H "Content-Type: application/json" \
  -d "{\"jobId\": \"$JOB_ID\", \"userId\": ${USER_ID:-null}}")

echo "Response:"
echo "$RESPONSE" | jq '.'

SUCCESS=$(echo "$RESPONSE" | jq -r '.success // false')
ERROR=$(echo "$RESPONSE" | jq -r '.error // empty')

echo ""
if [ "$SUCCESS" = "true" ]; then
  echo -e "${GREEN}✅ Edge Function call succeeded${NC}"
else
  echo -e "${RED}❌ Edge Function call failed: ${ERROR}${NC}"
fi

echo ""
echo ""

# ============================================================================
# Phase 5: Check Edge Function Logs
# ============================================================================
echo -e "${YELLOW}Phase 5: Checking Edge Function Logs${NC}"
echo ""

echo "Fetching recent logs for ${FUNCTION_NAME}..."
echo ""

LOGS=$(supabase functions logs ${FUNCTION_NAME} --project-ref ${PROJECT_REF} --limit 5 2>&1)

if echo "$LOGS" | grep -q "Using OAuth token from database"; then
  echo -e "${GREEN}✅ OAuth token used successfully${NC}"
elif echo "$LOGS" | grep -q "Using fallback token"; then
  echo -e "${YELLOW}⚠️ Fallback token used (OAuth not found or userId not provided)${NC}"
else
  echo -e "${BLUE}ℹ️ Logs:${NC}"
  echo "$LOGS" | tail -10
fi

echo ""
echo ""

# ============================================================================
# Phase 6: Verify Database State
# ============================================================================
echo -e "${YELLOW}Phase 6: Verifying Database State${NC}"
echo ""

UPDATED_JOB=$(curl -s -X POST "https://api.supabase.com/v1/projects/${PROJECT_REF}/database/query" \
  -H "Authorization: Bearer ${ACCESS_TOKEN}" \
  -H "Content-Type: application/json" \
  -d "{\"query\": \"SELECT id, clickup_task_id, clickup_task_url FROM job_submissions WHERE id = '\''${JOB_ID}'\''\"}")

TASK_ID=$(echo "$UPDATED_JOB" | jq -r '.[0].clickup_task_id // empty')
TASK_URL=$(echo "$UPDATED_JOB" | jq -r '.[0].clickup_task_url // empty')

if [ -n "$TASK_ID" ]; then
  echo -e "${GREEN}✅ ClickUp task created/updated:${NC}"
  echo "   Task ID: $TASK_ID"
  echo "   Task URL: $TASK_URL"
else
  echo -e "${RED}❌ No ClickUp task ID found in database${NC}"
fi

echo ""
echo ""

# ============================================================================
